import React from 'react';

export default function Internship() {
  return (
    <div className="auth-container">
      <h2>Internship Opportunities</h2>
      <p>Don't miss out on these amazing internships for students!</p>
      <img
        src="/internship.jpg"
        alt="Internship"
        style={{ maxWidth: '100%', borderRadius: '8px' }}
      />
      <p>Choose your career direction and grab the opportunity!</p>
      <a href="https://internshala.com/" target="_blank" rel="noreferrer">
        <button>Go to Internshala</button>
      </a>
    </div>
  );
}
